{
  "name": "MedHeadHunter",
  "description": "A web application for Russian-speaking healthcare organizations to publish vacancies for medical personnel. Candidates browse vacancies and contact employers directly."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback, useMemo } from 'react';
import { Header } from './components/Header';
import { VacancyList } from './components/VacancyList';
import { VacancyDetail } from './components/VacancyDetail';
import { PostVacancyFlow } from './components/PostVacancyFlow';
import type { Employer, Vacancy } from './types';
import { useLocalStorage } from './hooks/useLocalStorage';
import { initialEmployers, initialVacancies } from './constants';

type View = 'list' | 'detail' | 'post';

const App: React.FC = () => {
  const [view, setView] = useState<View>('list');
  const [selectedVacancyId, setSelectedVacancyId] = useState<string | null>(null);

  const [employers, setEmployers] = useLocalStorage<Employer[]>('employers', initialEmployers);
  const [vacancies, setVacancies] = useLocalStorage<Vacancy[]>('vacancies', initialVacancies);

  const handleSelectVacancy = useCallback((id: string) => {
    setSelectedVacancyId(id);
    setView('detail');
  }, []);

  const handleNavigate = useCallback((newView: View) => {
    setSelectedVacancyId(null);
    setView(newView);
  }, []);

  const handleVacancyPosted = useCallback((newVacancy: Vacancy, newEmployer?: Employer) => {
      if (newEmployer) {
          setEmployers(prev => [...prev, newEmployer]);
      }
      setVacancies(prev => [newVacancy, ...prev]);
      setView('list');
  }, [setEmployers, setVacancies]);

  const selectedVacancy = useMemo(() => {
    if (view !== 'detail' || !selectedVacancyId) return null;
    return vacancies.find(v => v.id === selectedVacancyId) || null;
  }, [view, selectedVacancyId, vacancies]);

  const selectedEmployer = useMemo(() => {
    if (!selectedVacancy) return null;
    return employers.find(e => e.id === selectedVacancy.employerId) || null;
  }, [selectedVacancy, employers]);

  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      <Header onNavigate={handleNavigate} />
      <main className="container mx-auto p-4 md:p-8">
        {view === 'list' && (
          <VacancyList vacancies={vacancies} employers={employers} onSelectVacancy={handleSelectVacancy} />
        )}
        {view === 'detail' && selectedVacancy && selectedEmployer && (
          <VacancyDetail vacancy={selectedVacancy} employer={selectedEmployer} onBack={() => handleNavigate('list')} />
        )}
        {view === 'post' && (
            <PostVacancyFlow employers={employers} onVacancyPosted={handleVacancyPosted} />
        )}
      </main>
      <footer className="text-center p-4 text-gray-500 text-sm mt-8">
        <p>&copy; {new Date().getFullYear()} MedHeadHunter. Все права защищены.</p>
      </footer>
    </div>
  );
};

export default App;

export interface Employer {
  id: string;
  organizationName: string;
  taxNumber: string; // ИНН
  officialAddress: string;
  contactPhonePrimary: string;
  contactPhoneSecondary?: string;
  contactEmail: string;
  website?: string;
  description?: string;
  createdAt: string;
}

export interface Vacancy {
  id: string;
  jobTitle: string;
  positionCategory: string; // 'Врач', 'Медсестра', 'Лаборант'
  city: string;
  employmentType: 'Полная занятость' | 'Частичная занятость' | 'Сменный график' | 'Договор';
  workSchedule?: string;
  salary?: string;
  experienceRequired?: string;
  educationRequired?: string;
  description: string;
  employerId: string;
  contactPhone: string;
  contactEmail:string;
  contactNote?: string;
  isPublished: boolean;
  createdAt: string;
}

import { useState, useEffect } from 'react';

export function useLocalStorage<T,>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(error);
      return initialValue;
    }
  });

  const setValue = (value: T | ((val: T) => T)) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
     try {
        const item = window.localStorage.getItem(key);
        if (!item) {
             window.localStorage.setItem(key, JSON.stringify(initialValue));
        }
     } catch(e) {
         console.error(e)
     }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [key, initialValue]);

  return [storedValue, setValue];
}

