import React, { useState, useCallback } from 'react';
import type { Employer, Vacancy } from '../types';
import { EmployerForm } from './EmployerForm';
import { VacancyForm } from './VacancyForm';

interface PostVacancyFlowProps {
  employers: Employer[];
  onVacancyPosted: (vacancy: Vacancy, newEmployer?: Employer) => void;
}

type Step = 'check' | 'employer' | 'vacancy';

export const PostVacancyFlow: React.FC<PostVacancyFlowProps> = ({ employers, onVacancyPosted }) => {
  const [step, setStep] = useState<Step>('check');
  const [currentEmployer, setCurrentEmployer] = useState<Employer | null>(null);
  const [taxNumber, setTaxNumber] = useState('');

  const handleCheckTaxNumber = () => {
    const existingEmployer = employers.find(e => e.taxNumber === taxNumber);
    if (existingEmployer) {
      setCurrentEmployer(existingEmployer);
    }
    setStep('vacancy');
  };

  const handleEmployerSubmit = useCallback((employerData: Omit<Employer, 'id' | 'createdAt'>) => {
      const newEmployer: Employer = {
          ...employerData,
          id: `emp_${Date.now()}`,
          createdAt: new Date().toISOString()
      };
      setCurrentEmployer(newEmployer);
      setStep('vacancy');
  }, []);

  const handleVacancySubmit = useCallback((vacancyData: Omit<Vacancy, 'id' | 'createdAt' | 'employerId' | 'isPublished'>) => {
    if (!currentEmployer && step !== 'vacancy') return; // Should not happen

    if (currentEmployer) {
       const isNewEmployer = !employers.some(e => e.id === currentEmployer.id);

       const newVacancy: Vacancy = {
            ...vacancyData,
            id: `vac_${Date.now()}`,
            createdAt: new Date().toISOString(),
            employerId: currentEmployer.id,
            isPublished: true,
        };

        onVacancyPosted(newVacancy, isNewEmployer ? currentEmployer : undefined);
    } else {
        // This flow is for existing employers, so currentEmployer must be set.
        // We handle new employer creation in handleEmployerSubmit.
        // If an existing employer was found via INN, that is set as currentEmployer.
        // A new employer form also sets currentEmployer.
        // So this else should ideally not be reachable if logic is correct.
        console.error("Cannot post vacancy without employer context.");
        alert("Произошла ошибка. Не удалось определить данные работодателя.");
    }

  }, [currentEmployer, onVacancyPosted, employers, step]);

  const renderStep = () => {
    switch (step) {
      case 'check':
        return (
          <div className="max-w-xl mx-auto bg-white p-8 rounded-lg shadow-xl">
            <h2 className="text-2xl font-bold text-gray-800 mb-1">Опубликовать вакансию</h2>
            <p className="text-gray-600 mb-6">Проверим, публиковались ли вы у нас ранее.</p>
            <div className="mb-4">
              <label htmlFor="tax_number_check" className="block text-gray-700 text-sm font-bold mb-2">
                ИНН вашей организации
              </label>
              <input
                id="tax_number_check"
                type="text"
                value={taxNumber}
                onChange={(e) => setTaxNumber(e.target.value)}
                className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                placeholder="Например, 7701234567"
              />
            </div>
            <button
              onClick={handleCheckTaxNumber}
              disabled={!taxNumber}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline disabled:bg-gray-400"
            >
              Продолжить
            </button>
            <p className="text-xs text-gray-500 mt-4">Если вы публикуетесь впервые, мы попросим вас заполнить данные организации на следующем шаге.</p>
          </div>
        );
      case 'vacancy':
        // If we came from check and didn't find an employer, we need to create one.
        if (!currentEmployer) {
           return <EmployerForm onSubmit={handleEmployerSubmit} initialTaxNumber={taxNumber} />;
        }
        return <VacancyForm employer={currentEmployer} onSubmit={handleVacancySubmit} />;
      default:
        return null;
    }
  };

  return <div className="container mx-auto">{renderStep()}</div>;
};

import React, { useState } from 'react';
import type { Employer } from '../types';

interface EmployerFormProps {
  initialTaxNumber?: string;
  onSubmit: (data: Omit<Employer, 'id' | 'createdAt'>) => void;
}

export const EmployerForm: React.FC<EmployerFormProps> = ({ onSubmit, initialTaxNumber = '' }) => {
  const [formData, setFormData] = useState({
    organizationName: '',
    taxNumber: initialTaxNumber,
    officialAddress: '',
    contactPhonePrimary: '',
    contactPhoneSecondary: '',
    contactEmail: '',
    website: '',
    description: '',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!formData.organizationName) newErrors.organizationName = 'Название организации обязательно';
    if (!formData.taxNumber) newErrors.taxNumber = 'ИНН обязателен';
    if (!/^\d{10}(\d{2})?$/.test(formData.taxNumber)) newErrors.taxNumber = 'ИНН должен состоять из 10 или 12 цифр';
    if (!formData.officialAddress) newErrors.officialAddress = 'Юридический адрес обязателен';
    if (!formData.contactPhonePrimary) newErrors.contactPhonePrimary = 'Основной телефон обязателен';
    if (!formData.contactEmail) newErrors.contactEmail = 'Email обязателен';
    if (formData.contactEmail && !/^\S+@\S+\.\S+$/.test(formData.contactEmail)) newErrors.contactEmail = 'Некорректный формат email';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onSubmit(formData);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-xl">
        <h2 className="text-2xl font-bold text-gray-800 mb-2">Данные организации</h2>
        <p className="text-gray-600 mb-6">Эта информация будет видна соискателям. Вы заполняете её один раз.</p>
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
