import React, { useState, useMemo } from 'react';
import type { Vacancy, Employer } from '../types';
import { VacancyCard } from './VacancyCard';
import { POSITION_CATEGORIES } from '../constants';
import { MagnifyingGlassIcon, MapPinIcon, TagIcon, RedCrossIcon } from './IconComponents';

interface VacancyListProps {
  vacancies: Vacancy[];
  employers: Employer[];
  onSelectVacancy: (id: string) => void;
}

export const VacancyList: React.FC<VacancyListProps> = ({ vacancies, employers, onSelectVacancy }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [cityFilter, setCityFilter] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');

  const cities = useMemo(() => {
      const citySet = new Set(vacancies.map(v => v.city).filter(Boolean));
      return Array.from(citySet).sort();
  }, [vacancies]);

  const filteredVacancies = useMemo(() => {
    return vacancies.filter(vacancy => {
      const employer = employers.find(e => e.id === vacancy.employerId);
      if (!employer) return false;

      const searchTermLower = searchTerm.toLowerCase();
      const matchesSearch =
        vacancy.jobTitle.toLowerCase().includes(searchTermLower) ||
        employer.organizationName.toLowerCase().includes(searchTermLower) ||
        vacancy.description.toLowerCase().includes(searchTermLower);

      const matchesCity = !cityFilter || vacancy.city.toLowerCase() === cityFilter.toLowerCase();
      const matchesCategory = !categoryFilter || vacancy.positionCategory === categoryFilter;

      return matchesSearch && matchesCity && matchesCategory;
    });
  }, [vacancies, employers, searchTerm, cityFilter, categoryFilter]);

  return (
    <div className="space-y-8">
      <div>
        <div className="flex items-center space-x-4 mb-2">
            <RedCrossIcon className="h-10 w-10 text-red-500" />
            <h1 className="text-3xl md:text-4xl font-bold text-gray-800">Найти вакансию</h1>
        </div>
        <p className="text-lg text-gray-600 ml-14">Актуальные предложения от ведущих медицинских организаций.</p>
      </div>

      <div className="bg-white p-4 rounded-lg shadow-md sticky top-[81px] z-5">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="relative">
            <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
            <input
              type="text"
              placeholder="Должность или ключевое слово"
              className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-blue-500 focus:border-blue-500"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="relative">
            <MapPinIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
            <select
              className="w-full pl-10 pr-4 py-2 border rounded-lg appearance-none bg-white focus:ring-blue-500 focus:border-blue-500"
              value={cityFilter}
              onChange={(e) => setCityFilter(e.target.value)}
            >
              <option value="">Все города</option>
              {cities.map(city => <option key={city} value={city}>{city}</option>)}
            </select>
          </div>
           <div className="relative">
            <TagIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
            <select
              className="w-full pl-10 pr-4 py-2 border rounded-lg appearance-none bg-white focus:ring-blue-500 focus:border-blue-500"
              value={categoryFilter}
              onChange={(e) => setCategoryFilter(e.target.value)}
            >
              <option value="">Все категории</option>
              {POSITION_CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
          </div>
        </div>
      </div>

      {filteredVacancies.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredVacancies.map(vacancy => {
            const employer = employers.find(e => e.id === vacancy.employerId);
            return employer ? (
                <VacancyCard
                key={vacancy.id}
                vacancy={vacancy}
                employer={employer}
                onSelectVacancy={onSelectVacancy}
                />
            ) : null;
            })}
        </div>
      ) : (
         <div className="text-center py-16 px-4 bg-white rounded-lg shadow-md">
            <h2 className="text-2xl font-semibold text-gray-700">Вакансий не найдено</h2>
            <p className="text-gray-500 mt-2">Попробуйте изменить параметры поиска или загляните позже.</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import type { Employer, Vacancy } from '../types';
import { EmployerForm } from './EmployerForm';
import { VacancyForm } from './VacancyForm';

interface PostVacancyFlowProps {
  employers: Employer[];
  onVacancyPosted: (vacancy: Vacancy, newEmployer?: Employer) => void;
}

type Step = 'check' | 'employer' | 'vacancy';

export const PostVacancyFlow: React.FC<PostVacancyFlowProps> = ({ employers, onVacancyPosted }) => {
  const [step, setStep] = useState<Step>('check');
  const [currentEmployer, setCurrentEmployer] = useState<Employer | null>(null);
  const [taxNumber, setTaxNumber] = useState('');

  const handleCheckTaxNumber = () => {
    const existingEmployer = employers.find(e => e.taxNumber === taxNumber);
    if (existingEmployer) {
      setCurrentEmployer(existingEmployer);
      setStep('vacancy');
    } else {
      setStep('employer');
    }
  };

  const handleEmployerSubmit = useCallback((employerData: Partial<Employer>) => {
      const newEmployer: Employer = {
          organizationName: employerData.organizationName || '',
          taxNumber: employerData.taxNumber || '',
          officialAddress: employerData.officialAddress || '',
          contactPhonePrimary: employerData.contactPhonePrimary || '',
          contactEmail: employerData.contactEmail || '',
          ...employerData,
          id: `emp_${Date.now()}`,
          createdAt: new Date().toISOString()
      };
      setCurrentEmployer(newEmployer);
      setStep('vacancy');
  }, []);

  const handleVacancySubmit = useCallback((vacancyData: Omit<Vacancy, 'id' | 'createdAt' | 'employerId' | 'isPublished'>) => {
    if (!currentEmployer) {
        console.error("Cannot post vacancy without employer context.");
        alert("Произошла ошибка. Не удалось определить данные работодателя.");
        return;
    }

    const isNewEmployer = !employers.some(e => e.id === currentEmployer.id);

    const newVacancy: Vacancy = {
        ...vacancyData,
        id: `vac_${Date.now()}`,
        createdAt: new Date().toISOString(),
        employerId: currentEmployer.id,
        isPublished: true,
    };

    onVacancyPosted(newVacancy, isNewEmployer ? currentEmployer : undefined);

  }, [currentEmployer, onVacancyPosted, employers]);

  const renderStep = () => {
    switch (step) {
      case 'check':
        return (
          <div className="max-w-xl mx-auto bg-white p-8 rounded-lg shadow-xl">
            <h2 className="text-2xl font-bold text-gray-800 mb-1">Опубликовать вакансию</h2>
            <p className="text-gray-600 mb-6">Проверим, публиковались ли вы у нас ранее.</p>
            <div className="mb-4">
              <label htmlFor="tax_number_check" className="block text-gray-700 text-sm font-bold mb-2">
                ИНН вашей организации
              </label>
              <input
                id="tax_number_check"
                type="text"
                value={taxNumber}
                onChange={(e) => setTaxNumber(e.target.value)}
                className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                placeholder="Например, 7701234567"
              />
            </div>
            <button
              onClick={handleCheckTaxNumber}
              disabled={!taxNumber}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline disabled:bg-gray-400"
            >
              Продолжить
            </button>
            <p className="text-xs text-gray-500 mt-4">Если вы публикуетесь впервые, мы попросим вас заполнить данные организации на следующем шаге.</p>
          </div>
        );
      case 'employer':
        return <EmployerForm 
            onSubmit={handleEmployerSubmit} 
            initialData={{ taxNumber }}
            buttonText="Сохранить и перейти к вакансии"
          />;
      case 'vacancy':
        if (!currentEmployer) {
            return (
              <div className="text-center text-red-500">
                Ошибка: данные работодателя не найдены. Пожалуйста, вернитесь на предыдущий шаг.
                <button onClick={() => setStep('check')} className="mt-4 px-4 py-2 bg-blue-600 text-white rounded">Назад</button>
              </div>
            );
        }
        return <VacancyForm employer={currentEmployer} onSubmit={handleVacancySubmit} />;
      default:
        return null;
    }
  };

  return <div className="container mx-auto">{renderStep()}</div>;
};

import React, { useState, useEffect } from 'react';
import type { Employer } from '../types';

interface EmployerFormProps {
  initialData?: Partial<Employer>;
  onSubmit: (data: Partial<Employer>) => void;
  onCancel?: () => void;
  buttonText: string;
}

const defaultState = {
    organizationName: '',
    taxNumber: '',
    officialAddress: '',
    contactPhonePrimary: '',
    contactPhoneSecondary: '',
    contactEmail: '',
    website: '',
    description: '',
};

export const EmployerForm: React.FC<EmployerFormProps> = ({ onSubmit, initialData, onCancel, buttonText }) => {
  const [formData, setFormData] = useState(defaultState);

  useEffect(() => {
    if (initialData) {
        setFormData(prev => ({ ...prev, ...initialData }));
    } else {
        setFormData(defaultState);
    }
  }, [initialData]);

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!formData.organizationName) newErrors.organizationName = 'Название организации обязательно';
    if (!formData.taxNumber) newErrors.taxNumber = 'ИНН обязателен';
    if (!/^\d{10}(\d{2})?$/.test(formData.taxNumber)) newErrors.taxNumber = 'ИНН должен состоять из 10 или 12 цифр';
    if (!formData.officialAddress) newErrors.officialAddress = 'Юридический адрес обязателен';
    if (!formData.contactPhonePrimary) newErrors.contactPhonePrimary = 'Основной телефон обязателен';
    if (!formData.contactEmail) newErrors.contactEmail = 'Email обязателен';
    if (formData.contactEmail && !/^\S+@\S+\.\S+$/.test(formData.contactEmail)) newErrors.contactEmail = 'Некорректный формат email';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onSubmit(formData);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const isEditMode = !!initialData?.id;

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-xl">
        <h2 className="text-2xl font-bold text-gray-800 mb-2">{isEditMode ? 'Редактирование организации' : 'Данные организации'}</h2>
        <p className="text-gray-600 mb-6">{isEditMode ? `Вы редактируете "${initialData?.organizationName}"` : 'Эта информация будет видна соискателям. Вы заполняете её один раз.'}</p>
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">Название организации *</label>
                <input type="text" name="organizationName" value={formData.organizationName} onChange={handleChange} className={`input ${errors.organizationName ? 'border-red-500' : ''}`} />
                {errors.organizationName && <p className="text-red-500 text-xs italic">{errors.organizationName}</p>}
            </div>
            <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">ИНН *</label>
                <input type="text" name="taxNumber" value={formData.taxNumber} onChange={handleChange} readOnly={isEditMode} className={`input ${errors.taxNumber ? 'border-red-500' : ''} ${isEditMode ? 'bg-gray-100' : ''}`} />
                {errors.taxNumber && <p className="text-red-500 text-xs italic">{errors.taxNumber}</p>}
            </div>
            <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">Юридический адрес *</label>
                <input type="text" name="officialAddress" value={formData.officialAddress} onChange={handleChange} className={`input ${errors.officialAddress ? 'border-red-500' : ''}`} />
                {errors.officialAddress && <p className="text-red-500 text-xs italic">{errors.officialAddress}</p>}
            </div>
             <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">Основной контактный телефон *</label>
                <input type="tel" name="contactPhonePrimary" value={formData.contactPhonePrimary} onChange={handleChange} className={`input ${errors.contactPhonePrimary ? 'border-red-500' : ''}`} />
                 {errors.contactPhonePrimary && <p className="text-red-500 text-xs italic">{errors.contactPhonePrimary}</p>}
            </div>
             <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">Дополнительный телефон</label>
                <input type="tel" name="contactPhoneSecondary" value={formData.contactPhoneSecondary} onChange={handleChange} className="input" />
            </div>
            <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">Контактный Email *</label>
                <input type="email" name="contactEmail" value={formData.contactEmail} onChange={handleChange} className={`input ${errors.contactEmail ? 'border-red-500' : ''}`} />
                {errors.contactEmail && <p className="text-red-500 text-xs italic">{errors.contactEmail}</p>}
            </div>
             <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">Сайт</label>
                <input type="url" name="website" value={formData.website} onChange={handleChange} className="input" placeholder="https://example.com" />
            </div>
            <div>
                <label className="block text-gray-700 text-sm font-bold mb-2">Краткое описание организации</label>
                <textarea name="description" value={formData.description} onChange={handleChange} className="input h-24" />
            </div>

            <div className="flex space-x-4">
                {onCancel && (
                    <button type="button" onClick={onCancel} className="w-full bg-gray-500 hover:bg-gray-600 text-white font-bold py-3 px-4 rounded focus:outline-none focus:shadow-outline">
                        Отмена
                    </button>
                )}
                <button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded focus:outline-none focus:shadow-outline">
                    {buttonText}
                </button>
            </div>
        </form>
        <style>{`
            .input {
                box-shadow: inset 0 1px 2px rgba(0,0,0,0.07);
                appearance: none;
                border: 1px solid #d2d6dc;
                border-radius: 0.375rem;
                width: 100%;
                padding: 0.5rem 0.75rem;
                color: #374151;
                line-height: 1.5;
            }
            .input:focus {
                outline: none;
                box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.5);
                border-color: #3b82f6;
            }
        `}</style>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import type { Vacancy, Employer } from '../types';
import { POSITION_CATEGORIES, EMPLOYMENT_TYPES } from '../constants';

interface VacancyFormProps {
  employer: Employer;
  initialData?: Vacancy;
  onSubmit: (data: Omit<Vacancy, 'id' | 'createdAt' | 'employerId' | 'isPublished'>) => void;
  onCancel?: () => void;
}

export const VacancyForm: React.FC<VacancyFormProps> = ({ employer, initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState({
    jobTitle: initialData?.jobTitle || '',
    positionCategory: initialData?.positionCategory || POSITION_CATEGORIES[0],
    city: initialData?.city || '',
    employmentType: initialData?.employmentType || EMPLOYMENT_TYPES[0],
    workSchedule: initialData?.workSchedule || '',
    salary: initialData?.salary || '',
    experienceRequired: initialData?.experienceRequired || '',
    educationRequired: initialData?.educationRequired || '',
    description: initialData?.description || '',
    contactPhone: initialData?.contactPhone || employer.contactPhonePrimary,
    contactEmail: initialData?.contactEmail || employer.contactEmail,
    contactNote: initialData?.contactNote || '',
  });

  useEffect(() => {
     if (initialData) {
        setFormData({
            jobTitle: initialData.jobTitle,
            positionCategory: initialData.positionCategory,
            city: initialData.city,
            employmentType: initialData.employmentType,
            workSchedule: initialData.workSchedule || '',
            salary: initialData.salary || '',
            experienceRequired: initialData.experienceRequired || '',
            educationRequired: initialData.educationRequired || '',
            description: initialData.description,
            contactPhone: initialData.contactPhone,
            contactEmail: initialData.contactEmail,
            contactNote: initialData.contactNote || '',
        });
     }
  }, [initialData]);

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!formData.jobTitle) newErrors.jobTitle = 'Название должности обязательно';
    if (!formData.description) newErrors.description = 'Описание вакансии обязательно';
    if (!formData.contactPhone && !formData.contactEmail) newErrors.contact = 'Укажите хотя бы телефон или email для связи';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onSubmit(formData);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const isEditMode = !!initialData;

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-xl">
        <div className="mb-6">
            <h2 className="text-2xl font-bold text-gray-800">{isEditMode ? 'Редактирование вакансии' : 'Новая вакансия'}</h2>
            <p className="text-gray-600">для организации «{employer.organizationName}»</p>
        </div>
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="label">Название должности *</label>
                <input type="text" name="jobTitle" value={formData.jobTitle} onChange={handleChange} className={`input ${errors.jobTitle ? 'border-red-500' : ''}`} />
                {errors.jobTitle && <p className="error-text">{errors.jobTitle}</p>}
            </div>
            <div>
                <label className="label">Категория</label>
                <select name="positionCategory" value={formData.positionCategory} onChange={handleChange} className="input">
                    {POSITION_CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
            </div>
            <div>
                <label className="label">Город</label>
                <input type="text" name="city" value={formData.city} onChange={handleChange} className="input" />
            </div>
            <div>
                <label className="label">Тип занятости</label>
                <select name="employmentType" value={formData.employmentType} onChange={handleChange} className="input">
                    {EMPLOYMENT_TYPES.map(type => <option key={type} value={type}>{type}</option>)}
                </select>
            </div>
             <div>
                <label className="label">График работы</label>
                <input type="text" name="workSchedule" value={formData.workSchedule} onChange={handleChange} className="input" placeholder="Например, 5/2 с 9:00 до 18:00"/>
            </div>
             <div>
                <label className="label">Зарплата</label>
                <input type="text" name="salary" value={formData.salary} onChange={handleChange} className="input" placeholder="Например, от 100 000 руб."/>
            </div>
             <div>
                <label className="label">Требуемый опыт</label>
                <input type="text" name="experienceRequired" value={formData.experienceRequired} onChange={handleChange} className="input" placeholder="Например, от 3 лет"/>
            </div>
            <div>
                <label className="label">Требуемое образование</label>
                <input type="text" name="educationRequired" value={formData.educationRequired} onChange={handleChange} className="input" placeholder="Например, высшее медицинское"/>
            </div>
            <div>
                <label className="label">Описание вакансии (обязанности, требования, условия) *</label>
                <textarea name="description" value={formData.description} onChange={handleChange} className={`input h-32 ${errors.description ? 'border-red-500' : ''}`} />
                {errors.description && <p className="error-text">{errors.description}</p>}
            </div>

            <div className="pt-4 border-t">
                <h3 className="text-lg font-semibold text-gray-700 mb-2">Контакты для соискателей</h3>
                <p className="text-sm text-gray-500 mb-4">Предзаполнены из данных организации, но вы можете их изменить для этой вакансии.</p>
                <div>
                    <label className="label">Контактный телефон</label>
                    <input type="tel" name="contactPhone" value={formData.contactPhone} onChange={handleChange} className="input" />
                </div>
                 <div>
                    <label className="label">Контактный Email</label>
                    <input type="email" name="contactEmail" value={formData.contactEmail} onChange={handleChange} className="input" />
                </div>
                {errors.contact && <p className="error-text">{errors.contact}</p>}
                 <div>
                    <label className="label">Примечание для соискателей</label>
                    <input type="text" name="contactNote" value={formData.contactNote} onChange={handleChange} className="input" placeholder="Например, «Звонить с 10:00 до 17:00»"/>
                </div>
            </div>

            <div className="flex space-x-4">
                 {onCancel && (
                    <button type="button" onClick={onCancel} className="w-full bg-gray-500 hover:bg-gray-600 text-white font-bold py-3 px-4 rounded focus:outline-none focus:shadow-outline">
                        Отмена
                    </button>
                )}
                <button type="submit" className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-4 rounded focus:outline-none focus:shadow-outline">
                    {isEditMode ? 'Сохранить изменения' : 'Опубликовать вакансию'}
                </button>
            </div>
        </form>
         <style>{`
            .label { display: block; color: #374151; font-size: 0.875rem; font-weight: 700; margin-bottom: 0.5rem; }
            .input {
                box-shadow: inset 0 1px 2px rgba(0,0,0,0.07);
                appearance: none;
                border: 1px solid #d2d6dc;
                border-radius: 0.375rem;
                width: 100%;
                padding: 0.5rem 0.75rem;
                color: #374151;
                line-height: 1.5;
            }
            .input:focus {
                outline: none;
                box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.5);
                border-color: #3b82f6;
            }
            .error-text { color: #ef4444; font-size: 0.75rem; font-style: italic; }
        `}</style>
    </div>
  );
};

