import React, { useState } from 'react';
import type { Employer, Vacancy } from '../types';
import { EmployerForm } from './EmployerForm';
import { VacancyForm } from './VacancyForm';
import { PencilIcon, TrashIcon } from './IconComponents';

interface AdminDashboardProps {
    employers: Employer[];
    vacancies: Vacancy[];
    onUpdateEmployer: (employer: Employer) => void;
    onDeleteEmployer: (employerId: string) => void;
    onUpdateVacancy: (vacancy: Vacancy) => void;
    onDeleteVacancy: (vacancyId: string) => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({
    employers,
    vacancies,
    onUpdateEmployer,
    onDeleteEmployer,
    onUpdateVacancy,
    onDeleteVacancy,
}) => {
    const [editingEmployer, setEditingEmployer] = useState<Employer | null>(null);
    const [editingVacancy, setEditingVacancy] = useState<Vacancy | null>(null);

    const handleEmployerSubmit = (formData: Partial<Employer>) => {
        if (!editingEmployer) return;
        onUpdateEmployer({ ...editingEmployer, ...formData });
        setEditingEmployer(null);
    };

    const handleVacancySubmit = (formData: Omit<Vacancy, 'id' | 'createdAt' | 'employerId' | 'isPublished'>) => {
        if (!editingVacancy) return;
        onUpdateVacancy({ ...editingVacancy, ...formData });
        setEditingVacancy(null);
    };

    if (editingEmployer) {
        return (
            <EmployerForm
                initialData={editingEmployer}
                onSubmit={handleEmployerSubmit}
                onCancel={() => setEditingEmployer(null)}
                buttonText="Сохранить изменения"
            />
        );
    }

    if (editingVacancy) {
        const employerForVacancy = employers.find(e => e.id === editingVacancy.employerId);
        if (!employerForVacancy) {
            return <p className="text-red-500">Ошибка: Работодатель для этой вакансии не найден.</p>;
        }
        return (
            <VacancyForm 
                employer={employerForVacancy}
                initialData={editingVacancy}
                onSubmit={handleVacancySubmit}
                onCancel={() => setEditingVacancy(null)}
            />
        );
    }

    return (
        <div className="space-y-12">
            <h1 className="text-3xl md:text-4xl font-bold text-gray-800">Панель администратора</h1>

            <div className="bg-white p-6 rounded-lg shadow-md">
                <h2 className="text-2xl font-semibold text-gray-700 mb-4">Управление работодателями ({employers.length})</h2>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left text-gray-500">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                            <tr>
                                <th scope="col" className="px-6 py-3">Организация</th>
                                <th scope="col" className="px-6 py-3">ИНН</th>
