                        <tbody>
                            {vacancies.map(vacancy => {
                                const employer = employers.find(e => e.id === vacancy.employerId);
                                return (
                                <tr key={vacancy.id} className="bg-white border-b hover:bg-gray-50">
                                    <td className="px-6 py-4 font-medium text-gray-900">{vacancy.jobTitle}</td>
                                    <td className="px-6 py-4">{employer?.organizationName || 'N/A'}</td>
                                    <td className="px-6 py-4">{vacancy.city}</td>
                                    <td className="px-6 py-4 flex space-x-2">
                                        <button onClick={() => setEditingVacancy(vacancy)} className="text-blue-600 hover:text-blue-800"><PencilIcon className="h-5 w-5"/></button>
                                        <button onClick={() => onDeleteVacancy(vacancy.id)} className="text-red-600 hover:text-red-800"><TrashIcon className="h-5 w-5"/></button>
                                    </td>
                                </tr>
                            )})}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useCallback, useMemo, useRef } from 'react';
import { Header } from './components/Header';
import { VacancyList } from './components/VacancyList';
import { VacancyDetail } from './components/VacancyDetail';
import { PostVacancyFlow } from './components/PostVacancyFlow';
import { AdminDashboard } from './components/AdminDashboard';
import type { Employer, Vacancy } from './types';
import { useLocalStorage } from './hooks/useLocalStorage';
import { initialEmployers, initialVacancies } from './constants';

type View = 'list' | 'detail' | 'post' | 'admin';

const App: React.FC = () => {
  const [view, setView] = useState<View>('list');
  const [isAdmin, setIsAdmin] = useState(false);
  const [selectedVacancyId, setSelectedVacancyId] = useState<string | null>(null);

  const [employers, setEmployers] = useLocalStorage<Employer[]>('employers', initialEmployers);
  const [vacancies, setVacancies] = useLocalStorage<Vacancy[]>('vacancies', initialVacancies);

  const [footerClickCount, setFooterClickCount] = useState(0);
  // Fix: Replaced NodeJS.Timeout with ReturnType<typeof setTimeout> for browser compatibility.
  const clickTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const handleSelectVacancy = useCallback((id: string) => {
    setSelectedVacancyId(id);
    setView('detail');
  }, []);

  const handleNavigate = useCallback((newView: View) => {
    if (newView === 'admin' && !isAdmin) return;
    setSelectedVacancyId(null);
    setView(newView);
  }, [isAdmin]);

  const handleVacancyPosted = useCallback((newVacancy: Vacancy, newEmployer?: Employer) => {
      if (newEmployer) {
          setEmployers(prev => [...prev, newEmployer]);
      }
      setVacancies(prev => [newVacancy, ...prev]);
      setView('list');
  }, [setEmployers, setVacancies]);

  // Admin CRUD Handlers
  const handleUpdateEmployer = (updatedEmployer: Employer) => {
    setEmployers(prev => prev.map(e => e.id === updatedEmployer.id ? updatedEmployer : e));
  };

  const handleDeleteEmployer = (employerId: string) => {
    if (window.confirm('Вы уверены, что хотите удалить этого работодателя и все его вакансии?')) {
        setVacancies(prev => prev.filter(v => v.employerId !== employerId));
        setEmployers(prev => prev.filter(e => e.id !== employerId));
    }
  };

  const handleUpdateVacancy = (updatedVacancy: Vacancy) => {
    setVacancies(prev => prev.map(v => v.id === updatedVacancy.id ? updatedVacancy : v));
  };

  const handleDeleteVacancy = (vacancyId: string) => {
    if (window.confirm('Вы уверены, что хотите удалить эту вакансию?')) {
        setVacancies(prev => prev.filter(v => v.id !== vacancyId));
    }
  };

  const handleAdminLogin = () => {
    const password = prompt('Введите пароль администратора:');
    if (password === 'ICUIvrDJdd@2026_Katsu' || password === 'BghJoe@7227++++') {
        setIsAdmin(true);
        setView('admin');
        alert('Доступ разрешен.');
    } else if (password) { // Don't show error if user cancels prompt
        alert('Неверный пароль.');
    }
    setFooterClickCount(0);
  };

  const handleFooterClick = () => {
    if (clickTimeoutRef.current) {
        clearTimeout(clickTimeoutRef.current);
    }

    const newCount = footerClickCount + 1;
    setFooterClickCount(newCount);

    if (newCount === 3) {
        handleAdminLogin();
    } else {
        clickTimeoutRef.current = setTimeout(() => {
            setFooterClickCount(0);
        }, 1000); // Reset after 1 second of inactivity
    }
  };


  const selectedVacancy = useMemo(() => {
    if (view !== 'detail' || !selectedVacancyId) return null;
    return vacancies.find(v => v.id === selectedVacancyId) || null;
  }, [view, selectedVacancyId, vacancies]);

  const selectedEmployer = useMemo(() => {
    if (!selectedVacancy) return null;
    return employers.find(e => e.id === selectedVacancy.employerId) || null;
  }, [selectedVacancy, employers]);

  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      <Header onNavigate={handleNavigate} isAdmin={isAdmin} />
      <main className="container mx-auto p-4 md:p-8">
        {view === 'list' && (
          <VacancyList vacancies={vacancies} employers={employers} onSelectVacancy={handleSelectVacancy} />
        )}
        {view === 'detail' && selectedVacancy && selectedEmployer && (
          <VacancyDetail vacancy={selectedVacancy} employer={selectedEmployer} onBack={() => handleNavigate('list')} />
        )}
        {view === 'post' && (
            <PostVacancyFlow employers={employers} onVacancyPosted={handleVacancyPosted} />
        )}
        {view === 'admin' && isAdmin && (
            <AdminDashboard 
                employers={employers}
                vacancies={vacancies}
                onUpdateEmployer={handleUpdateEmployer}
                onDeleteEmployer={handleDeleteEmployer}
                onUpdateVacancy={handleUpdateVacancy}
                onDeleteVacancy={handleDeleteVacancy}
            />
        )}
      </main>
      <footer className="text-center p-4 text-gray-500 text-sm mt-8">
        <p>
            &copy; <span onClick={handleFooterClick} className="cursor-pointer select-none">{new Date().getFullYear()}</span> MedHunter. Все права защищены.
        </p>
      </footer>
    </div>
  );
};

export default App;

