import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, Chat } from '@google/genai';
import { ChatBubbleLeftRightIcon, PaperAirplaneIcon, XMarkIcon } from './IconComponents';

interface Message {
    role: 'user' | 'model';
    text: string;
}

// Fix: Remove intermediate constant for API_KEY as per coding guidelines.
// const API_KEY = process.env.API_KEY;

export const Chatbot: React.FC = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [input, setInput] = useState('');
    const [messages, setMessages] = useState<Message[]>([
        { role: 'model', text: 'Здравствуйте! Я ваш карьерный консультант. Чем могу помочь сегодня?' }
    ]);
    const [isLoading, setIsLoading] = useState(false);
    const chatRef = useRef<Chat | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(scrollToBottom, [messages, isOpen]);

    useEffect(() => {
        if (!isOpen || chatRef.current) return;

        const initializeChat = async () => {
            // Fix: Use process.env.API_KEY directly as per guidelines.
            if (!process.env.API_KEY) {
                console.error("API_KEY is not set.");
                setMessages(prev => [...prev, { role: 'model', text: "Ошибка: Ключ API не настроен. Обратитесь к администратору."}])
                return;
            }
            try {
                // Fix: Use process.env.API_KEY directly as per guidelines.
                const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
                const model = 'gemini-3-flash-preview';
                const newChat = ai.chats.create({
                  model: model,
                  config: {
                    systemInstruction: 'You are a friendly and helpful career advisor specializing in the medical field in Russia. Provide concise and practical advice in Russian.',
                  }
                });
                chatRef.current = newChat;
            } catch (error) {
                console.error("Chat initialization error:", error);
                setMessages(prev => [...prev, { role: 'model', text: "Не удалось запустить чат. Попробуйте позже."}])
            }
        };

        initializeChat();
    }, [isOpen]);


    const handleSendMessage = useCallback(async () => {
        if (!input.trim() || isLoading || !chatRef.current) return;

        const userMessage: Message = { role: 'user', text: input };
        setMessages(prev => [...prev, userMessage]);
        setInput('');
        setIsLoading(true);

        try {
            const response = await chatRef.current.sendMessage({ message: userMessage.text });
            const modelMessage: Message = { role: 'model', text: response.text };
            setMessages(prev => [...prev, modelMessage]);
        } catch (error) {
            console.error("Error sending message:", error);
            setMessages(prev => [...prev, { role: 'model', text: 'К сожалению, произошла ошибка. Попробуйте еще раз.' }]);
        } finally {
            setIsLoading(false);
        }
    }, [input, isLoading]);

    const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            handleSendMessage();
        }
    }

    return (
        <>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="fixed bottom-6 right-6 bg-blue-600 text-white p-4 rounded-full shadow-lg hover:bg-blue-700 transition-transform transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 z-50"
                aria-label="Toggle AI Assistant"
            >
                <ChatBubbleLeftRightIcon className="h-8 w-8" />
            </button>

            {isOpen && (
                 <div className="fixed bottom-24 right-6 w-full max-w-sm h-full max-h-[600px] bg-white rounded-lg shadow-2xl flex flex-col z-50 transform transition-all duration-300 ease-out origin-bottom-right sm:w-96">
                    <header className="flex items-center justify-between p-4 bg-gray-100 border-b rounded-t-lg">
                        <h3 className="text-lg font-bold text-gray-800">Карьерный консультант</h3>
                        <button onClick={() => setIsOpen(false)} className="text-gray-500 hover:text-gray-800">
                            <XMarkIcon className="h-6 w-6" />
                        </button>
                    </header>

                    <div className="flex-1 p-4 overflow-y-auto bg-gray-50">
                        <div className="space-y-4">
                            {messages.map((msg, index) => (
                                <div key={index} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                    <div className={`max-w-xs lg:max-w-sm px-4 py-2 rounded-2xl ${msg.role === 'user' ? 'bg-blue-500 text-white' : 'bg-gray-200 text-gray-800'}`}>
                                        <p className="text-sm" style={{ whiteSpace: 'pre-wrap' }}>{msg.text}</p>
                                    </div>
                                </div>
                            ))}
                            {isLoading && (
                                <div className="flex justify-start">
                                    <div className="max-w-xs lg:max-w-sm px-4 py-2 rounded-2xl bg-gray-200 text-gray-800">
                                        <div className="flex items-center space-x-1">
                                            <span className="h-2 w-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                                            <span className="h-2 w-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                                            <span className="h-2 w-2 bg-gray-400 rounded-full animate-bounce"></span>
                                        </div>
                                    </div>
                                </div>
                            )}
                            <div ref={messagesEndRef} />
                        </div>
                    </div>

                    <div className="p-4 bg-white border-t rounded-b-lg">
                        <div className="flex items-center space-x-2">
                            <input
                                type="text"
                                value={input}
                                onChange={(e) => setInput(e.target.value)}
                                onKeyPress={handleKeyPress}
                                placeholder="Спросите о карьере..."
                                className="w-full px-4 py-2 border rounded-full focus:outline-none focus:ring-2 focus:ring-blue-500"
                                disabled={isLoading}
                            />
                            <button onClick={handleSendMessage} disabled={isLoading || !input.trim()} className="bg-blue-600 text-white p-3 rounded-full hover:bg-blue-700 disabled:bg-gray-400 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500">
                                <PaperAirplaneIcon className="h-5 w-5"/>
                            </button>
                        </div>
                    </div>
                 </div>
            )}
        </>
    );
};

