import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import type { Vacancy, Employer } from '../types';
import { POSITION_CATEGORIES, EMPLOYMENT_TYPES } from '../constants';
import { SparklesIcon } from './IconComponents';

interface VacancyFormProps {
  employer: Employer;
  initialData?: Vacancy;
  onSubmit: (data: Omit<Vacancy, 'id' | 'createdAt' | 'employerId' | 'isPublished'>) => void;
  onCancel?: () => void;
}

export const VacancyForm: React.FC<VacancyFormProps> = ({ employer, initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState({
    jobTitle: initialData?.jobTitle || '',
    positionCategory: initialData?.positionCategory || POSITION_CATEGORIES[0],
    city: initialData?.city || '',
    employmentType: initialData?.employmentType || EMPLOYMENT_TYPES[0],
    workSchedule: initialData?.workSchedule || '',
    salary: initialData?.salary || '',
    experienceRequired: initialData?.experienceRequired || '',
    educationRequired: initialData?.educationRequired || '',
    description: initialData?.description || '',
    contactPhone: initialData?.contactPhone || employer.contactPhonePrimary,
    contactEmail: initialData?.contactEmail || employer.contactEmail,
    contactNote: initialData?.contactNote || '',
  });

  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
     if (initialData) {
        setFormData({
            jobTitle: initialData.jobTitle,
            positionCategory: initialData.positionCategory,
            city: initialData.city,
            employmentType: initialData.employmentType,
            workSchedule: initialData.workSchedule || '',
            salary: initialData.salary || '',
            experienceRequired: initialData.experienceRequired || '',
            educationRequired: initialData.educationRequired || '',
            description: initialData.description,
            contactPhone: initialData.contactPhone,
            contactEmail: initialData.contactEmail,
            contactNote: initialData.contactNote || '',
        });
     }
  }, [initialData]);

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!formData.jobTitle) newErrors.jobTitle = 'Название должности обязательно';
    if (!formData.description) newErrors.description = 'Описание вакансии обязательно';
    if (!formData.contactPhone && !formData.contactEmail) newErrors.contact = 'Укажите хотя бы телефон или email для связи';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onSubmit(formData);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleGenerateDescription = async () => {
      if (!formData.jobTitle) {
          alert("Пожалуйста, сначала укажите название должности.");
          return;
      }
      setIsGenerating(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const prompt = `Напиши профессиональное и привлекательное описание вакансии на русском языке для должности "${formData.jobTitle}" в категории "${formData.positionCategory}".
Требуемый опыт: "${formData.experienceRequired || 'не указан'}".
Компания: "${employer.organizationName}".
Описание должно включать разделы: "Обязанности", "Требования", "Условия".
Сделай текст структурированным, ясным и легким для чтения. Не используй markdown.`;

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: prompt,
          });

          const text = response.text;
          if (text) {
              setFormData(prev => ({ ...prev, description: text }));
          } else {
              throw new Error("API did not return text.");
          }
      } catch (error) {
          console.error("Error generating description:", error);
          alert("Не удалось сгенерировать описание. Попробуйте еще раз.");
      } finally {
          setIsGenerating(false);
      }
  };

  const isEditMode = !!initialData;

  return (
    <div className="max-w-2xl mx-auto bg-white p-8 rounded-lg shadow-xl">
        <div className="mb-6">
            <h2 className="text-2xl font-bold text-gray-800">{isEditMode ? 'Редактирование вакансии' : 'Новая вакансия'}</h2>
            <p className="text-gray-600">для организации «{employer.organizationName}»</p>
        </div>
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="label">Название должности *</label>
                <input type="text" name="jobTitle" value={formData.jobTitle} onChange={handleChange} className={`input ${errors.jobTitle ? 'border-red-500' : ''}`} />
                {errors.jobTitle && <p className="error-text">{errors.jobTitle}</p>}
            </div>
            <div>
                <label className="label">Категория</label>
                <select name="positionCategory" value={formData.positionCategory} onChange={handleChange} className="input">
                    {POSITION_CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                </select>
            </div>
            <div>
                <label className="label">Город</label>
                <input type="text" name="city" value={formData.city} onChange={handleChange} className="input" />
            </div>
            <div>
                <label className="label">Тип занятости</label>
                <select name="employmentType" value={formData.employmentType} onChange={handleChange} className="input">
                    {EMPLOYMENT_TYPES.map(type => <option key={type} value={type}>{type}</option>)}
                </select>
            </div>
             <div>
                <label className="label">График работы</label>
                <input type="text" name="workSchedule" value={formData.workSchedule} onChange={handleChange} className="input" placeholder="Например, 5/2 с 9:00 до 18:00"/>
            </div>
             <div>
                <label className="label">Зарплата</label>
                <input type="text" name="salary" value={formData.salary} onChange={handleChange} className="input" placeholder="Например, от 100 000 руб."/>
            </div>
             <div>
                <label className="label">Требуемый опыт</label>
                <input type="text" name="experienceRequired" value={formData.experienceRequired} onChange={handleChange} className="input" placeholder="Например, от 3 лет"/>
            </div>
            <div>
                <label className="label">Требуемое образование</label>
                <input type="text" name="educationRequired" value={formData.educationRequired} onChange={handleChange} className="input" placeholder="Например, высшее медицинское"/>
            </div>
            <div>
                <div className="flex justify-between items-center mb-2">
                    <label className="label mb-0">Описание вакансии (обязанности, требования, условия) *</label>
                    <button 
                        type="button" 
                        onClick={handleGenerateDescription}
                        disabled={isGenerating}
                        className="flex items-center text-sm text-indigo-600 hover:text-indigo-800 font-semibold disabled:text-gray-400 disabled:cursor-not-allowed"
                    >
                       <SparklesIcon className="h-4 w-4 mr-1"/>
                       {isGenerating ? 'Генерация...' : 'Сгенерировать с AI'}
                    </button>
                </div>
                <textarea name="description" value={formData.description} onChange={handleChange} className={`input h-48 ${errors.description ? 'border-red-500' : ''}`} />
                {errors.description && <p className="error-text">{errors.description}</p>}
            </div>

            <div className="pt-4 border-t">
                <h3 className="text-lg font-semibold text-gray-700 mb-2">Контакты для соискателей</h3>
                <p className="text-sm text-gray-500 mb-4">Предзаполнены из данных организации, но вы можете их изменить для этой вакансии.</p>
                <div>
                    <label className="label">Контактный телефон</label>
                    <input type="tel" name="contactPhone" value={formData.contactPhone} onChange={handleChange} className="input" />
                </div>
                 <div>
                    <label className="label">Контактный Email</label>
                    <input type="email" name="contactEmail" value={formData.contactEmail} onChange={handleChange} className="input" />
                </div>
                {errors.contact && <p className="error-text">{errors.contact}</p>}
                 <div>
                    <label className="label">Примечание для соискателей</label>
                    <input type="text" name="contactNote" value={formData.contactNote} onChange={handleChange} className="input" placeholder="Например, «Звонить с 10:00 до 17:00»"/>
                </div>
            </div>

            <div className="flex space-x-4 pt-4">
                 {onCancel && (
                    <button type="button" onClick={onCancel} className="w-full bg-gray-500 hover:bg-gray-600 text-white font-bold py-3 px-4 rounded focus:outline-none focus:shadow-outline">
                        Отмена
                    </button>
                )}
                <button type="submit" className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-4 rounded focus:outline-none focus:shadow-outline">
                    {isEditMode ? 'Сохранить изменения' : 'Опубликовать вакансию'}
                </button>
            </div>
        </form>
         <style>{`
            .label { display: block; color: #374151; font-size: 0.875rem; font-weight: 700; margin-bottom: 0.5rem; }
            .input {
                box-shadow: inset 0 1px 2px rgba(0,0,0,0.07);
                appearance: none;
                border: 1px solid #d2d6dc;
                border-radius: 0.375rem;
                width: 100%;
                padding: 0.5rem 0.75rem;
                color: #374151;
                line-height: 1.5;
            }
            .input:focus {
                outline: none;
                box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.5);
                border-color: #3b82f6;
            }
            .error-text { color: #ef4444; font-size: 0.75rem; font-style: italic; }
        `}</style>
    </div>
  );
};

import React, { useState } from 'react';
import type { Employer, Vacancy } from '../types';
import { EmployerForm } from './EmployerForm';
import { VacancyForm } from './VacancyForm';
import { PencilIcon, TrashIcon, BuildingOffice2Icon, BriefcaseIcon } from './IconComponents';

interface AdminDashboardProps {
    employers: Employer[];
    vacancies: Vacancy[];
    onUpdateEmployer: (employer: Employer) => void;
    onDeleteEmployer: (employerId: string) => void;
    onUpdateVacancy: (vacancy: Vacancy) => void;
    onDeleteVacancy: (vacancyId: string) => void;
    onAddNewEmployer: (employerData: Partial<Employer>) => void;
    onAddNewVacancy: (vacancyData: Omit<Vacancy, 'id' | 'createdAt' | 'employerId' | 'isPublished'>, employerId: string) => void;
}

type Mode = 'list' | 'edit_employer' | 'create_employer' | 'edit_vacancy' | 'create_vacancy';

const StatCard: React.FC<{ icon: React.ReactNode, title: string, value: number | string }> = ({ icon, title, value }) => (
    <div className="bg-white p-6 rounded-lg shadow-md flex items-center space-x-4">
        <div className="bg-blue-100 p-3 rounded-full">
            {icon}
        </div>
        <div>
            <p className="text-sm text-gray-500">{title}</p>
            <p className="text-2xl font-bold text-gray-800">{value}</p>
        </div>
    </div>
);


export const AdminDashboard: React.FC<AdminDashboardProps> = ({
    employers,
    vacancies,
    onUpdateEmployer,
    onDeleteEmployer,
    onUpdateVacancy,
    onDeleteVacancy,
    onAddNewEmployer,
    onAddNewVacancy,
}) => {
    const [mode, setMode] = useState<Mode>('list');
    const [selectedItem, setSelectedItem] = useState<Employer | Vacancy | null>(null);
    const [employerForNewVacancy, setEmployerForNewVacancy] = useState<Employer | null>(null);

    const handleCancel = () => {
        setMode('list');
        setSelectedItem(null);
        setEmployerForNewVacancy(null);
    };

    const handleEmployerSubmit = (formData: Partial<Employer>) => {
        if (mode === 'create_employer') {
            onAddNewEmployer(formData);
        } else if (mode === 'edit_employer' && selectedItem) {
            onUpdateEmployer({ ...(selectedItem as Employer), ...formData });
        }
        handleCancel();
    };

    const handleVacancySubmit = (formData: Omit<Vacancy, 'id' | 'createdAt' | 'employerId' | 'isPublished'>) => {
        if (mode === 'create_vacancy' && employerForNewVacancy) {
            onAddNewVacancy(formData, employerForNewVacancy.id);
        } else if (mode === 'edit_vacancy' && selectedItem) {
            onUpdateVacancy({ ...(selectedItem as Vacancy), ...formData });
        }
        handleCancel();
    };

    if (mode === 'create_employer') {
        return <EmployerForm onSubmit={handleEmployerSubmit} onCancel={handleCancel} buttonText="Добавить работодателя" />;
    }
    if (mode === 'edit_employer' && selectedItem) {
        return <EmployerForm initialData={selectedItem as Employer} onSubmit={handleEmployerSubmit} onCancel={handleCancel} buttonText="Сохранить изменения" />;
    }
    if (mode === 'create_vacancy') {
        if (!employerForNewVacancy) {
            return (
                <div className="max-w-xl mx-auto bg-white p-8 rounded-lg shadow-xl">
                    <h2 className="text-2xl font-bold text-gray-800 mb-1">Создание вакансии</h2>
                    <p className="text-gray-600 mb-6">Шаг 1: Выберите работодателя для новой вакансии.</p>
                    <div className="mb-4">
                        <label htmlFor="employer-select" className="block text-gray-700 text-sm font-bold mb-2">
                            Организация
                        </label>
                        <select
                            id="employer-select"
                            onChange={(e) => {
                                const emp = employers.find(emp => emp.id === e.target.value);
                                if (emp) setEmployerForNewVacancy(emp);
                            }}
                            defaultValue=""
                            className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                        >
                            <option value="" disabled>-- Выберите организацию --</option>
                            {employers.map(emp => <option key={emp.id} value={emp.id}>{emp.organizationName} ({emp.taxNumber})</option>)}
                        </select>
                    </div>
                    <div className="flex justify-end space-x-4 mt-6">
                        <button onClick={handleCancel} className="bg-gray-500 hover:bg-gray-600 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline">
                            Отмена
                        </button>
                    </div>
                </div>
            );
        }
        return <VacancyForm employer={employerForNewVacancy} onSubmit={handleVacancySubmit} onCancel={handleCancel} />;
    }
    if (mode === 'edit_vacancy' && selectedItem) {
        const employerForVacancy = employers.find(e => e.id === (selectedItem as Vacancy).employerId);
        if (!employerForVacancy) {
            return <p className="text-red-500">Ошибка: Работодатель для этой вакансии не найден.</p>;
        }
        return <VacancyForm employer={employerForVacancy} initialData={selectedItem as Vacancy} onSubmit={handleVacancySubmit} onCancel={handleCancel} />;
    }

    return (
        <div className="space-y-8">
            <div>
                <h1 className="text-3xl md:text-4xl font-bold text-gray-800 mb-6">Панель администратора</h1>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
                    <StatCard icon={<BuildingOffice2Icon className="h-6 w-6 text-blue-600" />} title="Всего работодателей" value={employers.length} />
                    <StatCard icon={<BriefcaseIcon className="h-6 w-6 text-blue-600" />} title="Всего вакансий" value={vacancies.length} />
                </div>

                <div className="flex justify-start space-x-4">
                    <button onClick={() => setMode('create_employer')} className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline">
                        + Добавить работодателя
                    </button>
                     <button onClick={() => setMode('create_vacancy')} className="bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline">
                        + Добавить вакансию
                    </button>
                </div>
            </div>

            <div className="bg-white p-6 rounded-lg shadow-md">
                <h2 className="text-2xl font-semibold text-gray-700 mb-4">Управление работодателями</h2>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left text-gray-500">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                            <tr>
                                <th scope="col" className="px-6 py-3">Организация</th>
                                <th scope="col" className="px-6 py-3">ИНН</th>
                                <th scope="col" className="px-6 py-3">Email</th>
                                <th scope="col" className="px-6 py-3">Действия</th>
                            </tr>
                        </thead>
                        <tbody>
                            {employers.map(employer => (
                                <tr key={employer.id} className="bg-white border-b hover:bg-gray-50">
                                    <td className="px-6 py-4 font-medium text-gray-900">{employer.organizationName}</td>
                                    <td className="px-6 py-4">{employer.taxNumber}</td>
                                    <td className="px-6 py-4">{employer.contactEmail}</td>
                                    <td className="px-6 py-4 flex space-x-2">
                                        <button onClick={() => { setSelectedItem(employer); setMode('edit_employer'); }} className="text-blue-600 hover:text-blue-800"><PencilIcon className="h-5 w-5"/></button>
                                        <button onClick={() => onDeleteEmployer(employer.id)} className="text-red-600 hover:text-red-800"><TrashIcon className="h-5 w-5"/></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            <div className="bg-white p-6 rounded-lg shadow-md">
                <h2 className="text-2xl font-semibold text-gray-700 mb-4">Управление вакансиями</h2>
                 <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left text-gray-500">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                            <tr>
                                <th scope="col" className="px-6 py-3">Должность</th>
                                <th scope="col" className="px-6 py-3">Работодатель</th>
                                <th scope="col" className="px-6 py-3">Город</th>
                                <th scope="col" className="px-6 py-3">Действия</th>
                            </tr>
                        </thead>
                        <tbody>
                            {vacancies.map(vacancy => {
                                const employer = employers.find(e => e.id === vacancy.employerId);
                                return (
                                <tr key={vacancy.id} className="bg-white border-b hover:bg-gray-50">
                                    <td className="px-6 py-4 font-medium text-gray-900">{vacancy.jobTitle}</td>
                                    <td className="px-6 py-4">{employer?.organizationName || 'N/A'}</td>
                                    <td className="px-6 py-4">{vacancy.city}</td>
                                    <td className="px-6 py-4 flex space-x-2">
                                        <button onClick={() => { setSelectedItem(vacancy); setMode('edit_vacancy'); }} className="text-blue-600 hover:text-blue-800"><PencilIcon className="h-5 w-5"/></button>
                                        <button onClick={() => onDeleteVacancy(vacancy.id)} className="text-red-600 hover:text-red-800"><TrashIcon className="h-5 w-5"/></button>
                                    </td>
                                </tr>
                            )})}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

